arguments.old_string:
// Convenience: fetch one row
function dbOne(string $sql, array $params = []): ?array {
    $db = getDB();
    if (!$db) return null;
    $st = $db->prepare($sql);
    $st->execute($params);
    $row = $st->fetch();
    return $row ?: null;
}

// Convenience: fetch many rows
function dbAll(string $sql, array $params = []): array {
    $db = getDB();
    if (!$db) return [];
    $st = $db->prepare($sql);
    $st->execute($params);
    return $st->fetchAll();
}

