const fs = require('fs');
const zlib = require('zlib');

function makePng(r,g,b,size=48){
  const w=size,h=size;
  const rows=[];
  for(let y=0;y<h;y++){const row=Buffer.alloc(w*3+1);row[0]=0;for(let x=0;x<w;x++){row[1+x*3]=r;row[2+x*3]=g;row[3+x*3]=b;}rows.push(row);}
  const raw=Buffer.concat(rows);
  const compressed=zlib.deflateSync(raw);
  function crc32(buf){let c=0xffffffff;for(const b of buf){c=(c>>>8)^crcTable[(c^b)&0xff];}return (c^0xffffffff)>>>0;}
  const crcTable=[];for(let n=0;n<256;n++){let c=n;for(let k=0;k<8;k++)c=c&1?0xedb88320^(c>>>1):c>>>1;crcTable[n]=c;}
  function chunk(type,data){const t=Buffer.from(type);const len=Buffer.alloc(4);len.writeUInt32BE(data.length);const crcBuf=Buffer.alloc(4);crcBuf.writeUInt32BE(crc32(Buffer.concat([t,data])));return Buffer.concat([len,t,data,crcBuf]);}
  const ihdr=Buffer.alloc(13);ihdr.writeUInt32BE(w,0);ihdr.writeUInt32BE(h,4);ihdr[8]=8;ihdr[9]=2;
  return Buffer.concat([Buffer.from('89504e470d0a1a0a','hex'),chunk('IHDR',ihdr),chunk('IDAT',compressed),chunk('IEND',Buffer.alloc(0))]);
}
