     1→import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
     2→import AsyncStorage from '@react-native-async-storage/async-storage';
     3→import { apiProfile, User } from '@/lib/api';
     4→
     5→interface AuthState {
     6→  user: User | null;
     7→  token: string | null;
     8→  loading: boolean;
     9→  login: (token: string, user: User) => Promise<void>;
    10→  logout: () => Promise<void>;
    11→  refreshUser: () => Promise<void>;
    12→}
    13→
    14→const AuthContext = createContext<AuthState>({} as AuthState);
    15→
    16→export function AuthProvider({ children }: { children: ReactNode }) {
    17→  const [user, setUser] = useState<User | null>(null);
    18→  const [token, setToken] = useState<string | null>(null);
    19→  const [loading, setLoading] = useState(true);
    20→
    21→  useEffect(() => {
    22→    (async () => {
    23→      const t = await AsyncStorage.getItem('ce_token');
    24→      if (t) {
    25→        setToken(t);
    26→        try {
    27→          const { user: u } = await apiProfile();
    28→          setUser(u);
    29→        } catch {
    30→          await AsyncStorage.removeItem('ce_token');
    31→        }
    32→      }
    33→      setLoading(false);
    34→    })();
    35→  }, []);
    36→
    37→  const login = async (t: string, u: User) => {
    38→    await AsyncStorage.setItem('ce_token', t);
    39→    setToken(t);
    40→    setUser(u);
    41→  };
    42→
    43→  const logout = async () => {
    44→    await AsyncStorage.removeItem('ce_token');
    45→    setToken(null);
    46→    setUser(null);
    47→  };
    48→
    49→  const refreshUser = async () => {
    50→    try {
    51→      const { user: u } = await apiProfile();
    52→      setUser(u);
    53→    } catch {}
    54→  };
    55→
    56→  return (
    57→    <AuthContext.Provider value={{ user, token, loading, login, logout, refreshUser }}>
    58→      {children}
    59→    </AuthContext.Provider>
    60→  );
    61→}
    62→
    63→export const useAuth = () => useContext(AuthContext);
